def solve(ftp_data, parcel_requests):
    # Parse the FTP data
    flights = parse_ftp_data(ftp_data)

    # Match parcel requests to available flights
    reservations = []
    for request in parcel_requests:
        matched_flight = match_request_to_flight(request, flights)
        if matched_flight:
            reservations.append(create_reservation(request, matched_flight))

    return reservations

def parse_ftp_data(ftp_data):
    # Dummy implementation for parsing FTP data
    flights = []
    for line in ftp_data.splitlines():
        flight_info = line.split(',')
        flights.append({
            'flight_number': flight_info[0],
            'departure_time': flight_info[1],
            'capacity': int(flight_info[2])
        })
    return flights

def match_request_to_flight(request, flights):
    for flight in flights:
        if flight['capacity'] >= request['weight']:
            return flight
    return None

def create_reservation(request, flight):
    return {
        'request_id': request['id'],
        'flight_number': flight['flight_number'],
        'weight': request['weight']
    }
